:root {
  --bg: #0a0a0a;
  --link-color: #e4e3db;
  --overlay-bg: #000;
}

* {
  margin: 0;
  padding: 0;
}

html,
body {
  width: 100vw;
  height: 100vh;
  font-family: "Roslindale Display Condensed";
}

#logo {
  display: none !important;
}

.logo {
  position: fixed;
  margin: 3em;
  z-index: 10000;
}

.logo .logo-wrapper a {
  text-decoration: none;
  font-family: "Canopee";
  text-transform: uppercase;
  color: var(--text-color);
  line-height: 1;
}

@media (max-width: 900px) {
  .logo .logo-wrapper a {
    font-size: 4vw;
  }
}

/* overlay  */
.overlay {
  position: fixed;
  width: 100vw;
  height: 102vh;
  overflow: hidden;
  top: -2vh;
  left: 0;
  z-index: 1;
  pointer-events: none;
}

svg path {
  fill: var(--overlay-bg);
}

/* toggle btn */
#toggle-btn {
  position: absolute;
  top: 0;
  right: 0;
  width: 100px;
  height: 100px;
  display: flex;
  justify-content: center;
  align-items: center;
  margin: 2em;
  z-index: 2;
  cursor: pointer;
}

.btn-outline {
  position: absolute;
  width: 100px;
  height: 100px;
  border: 1px solid var(--link-color);
}

.btn-outline-1 {
  /* border-radius: 60% 40% 30% 70% / 60% 30% 70% 40%; */
  border-radius: 100%;
  animation: morph 4s linear infinite;
}

.btn-outline-2 {
  /* border-radius: 53% 47% 43% 57% / 51% 39% 61% 49%; */
  border-radius: 100%;
}

